#!/usr/bin/env bash
set -euo pipefail

# Replace the repository with the controlled RepoDiet hard-test fixture.
find . -mindepth 1 -maxdepth 1   ! -name .git   ! -name scripts   ! -name .github   -exec rm -rf {} +
rm -rf src public migrations tests
mkdir -p /tmp/repodiet-fixture
printf '%s' '' | base64 --decode | tar -xzf - -C /tmp/repodiet-fixture
cp -a /tmp/repodiet-fixture/. .
rm -rf /tmp/repodiet-fixture
